#include &lt;string&gt;

&#x2F;&#x2F; 注意应该先做除法再做乘法，否则会溢出!!!
#define BLOCK_LOW(rank, N, p_number) ((N*rank&#x2F;p_number))
#define BLOCK_HIGH(rank, N, p_number) ((N*(rank+1)&#x2F;p_number)-1)
&#x2F;&#x2F; cache相关参数
#define CACHESIZE 2300000
#define LINESIZE 64

int main(int argc, char* argv[]) &#123;
    MPI_Init(&amp;argc, &amp;argv);

    int rank, size, k &#x3D; 3, index &#x3D; 0, block &#x3D; 0;
    int count &#x3D; 0, global_count &#x3D; 0;
    MPI_Comm_rank(MPI_COMM_WORLD, &amp;rank);
    MPI_Comm_size(MPI_COMM_WORLD, &amp;size);

    &#x2F;&#x2F; 需要有两个命令行参数，否则报错
    if (argc !&#x3D; 2) &#123;
        if (!rank) printf(&quot;Command line: %s &lt;m&gt; \n&quot;, argv[0]);
        MPI_Finalize(); exit(-1);
    &#125;

    MPI_Barrier(MPI_COMM_WORLD);
    double elapsed_time &#x3D; -MPI_Wtime();

    &#x2F;&#x2F; 确定各进程的计算区域
    long long N &#x3D; std::stoll(argv[1]);
    long long low  &#x3D; 1 + BLOCK_LOW(rank, N, size);
    if(!(low&amp;1)) low++;
    long long block_low &#x3D; low; &#x2F;&#x2F; 分块，第一块的起始位置
    long long high &#x3D; 1 + BLOCK_HIGH(rank, N, size);
    if(!(high&amp;1)) high--;

    int sqrt_n &#x3D; (int)sqrt((double)N);
    int sqrt_2n &#x3D; (int)sqrt((double)sqrt_n);

    &#x2F;&#x2F; 进程过多，导致计算结果不正确的情况
    if((2 + size) &gt; sqrt_n) &#123;
        if (!rank) printf(&quot;Too many processes.\n&quot;);
        MPI_Finalize(); exit(-1);
    &#125;

    &#x2F;&#x2F; 两个奇数之间奇数的个数
    int local_size &#x3D; ((high - low) &gt;&gt; 1) + 1;  
    int table_size &#x3D; ((sqrt_n - 3) &gt;&gt; 1) + 1;  
    int block_size &#x3D; (local_size%CACHESIZE &#x3D;&#x3D; 0)?
    (local_size&#x2F;CACHESIZE):((local_size&#x2F;CACHESIZE)+1);

    &#x2F;&#x2F; 使用char节省空间
    char *flags &#x3D; (char*)malloc(sizeof(char)*local_size);
    char *table &#x3D; (char*)malloc(sizeof(char)*table_size);
    if(flags &#x3D;&#x3D; NULL || table &#x3D;&#x3D; NULL) &#123;
        if(!rank) printf(&quot;内存分配失败！程序退出\n&quot;); 
        MPI_Finalize(); exit(-1);
    &#125;
    memset(flags, 0, local_size);
    memset(table, 0, table_size);

    &#x2F;&#x2F; 确定k表中的素数
    while(k &lt; sqrt_2n) &#123;
        int cur &#x3D; (k &lt;&lt; 1) + k;
        while(cur &lt; sqrt_n) &#123;
            table[(cur-3)&gt;&gt;1] &#x3D; 1;
            cur +&#x3D; (k &lt;&lt; 1);
        &#125;
        while(table[++index]);
        k &#x3D; (index &lt;&lt; 1) + 3;
    &#125;

    &#x2F;&#x2F; 大循环
    while(block &lt; block_size) &#123;
        index &#x3D; 0; k &#x3D; 3;
        long long block_high &#x3D; block_low + CACHESIZE * 2;
        while(k &lt; sqrt_n) &#123;
            &#x2F;&#x2F; block_low之后第一个k的倍数且为奇数
            long long cur &#x3D; ((block_low &#x2F; k) + 1) * k;
            if(!(cur&amp;1)) &#123;
                if(cur-block_low &#x3D;&#x3D; k) cur &#x3D; block_low;
                else cur +&#x3D; k;
            &#125;
            &#x2F;&#x2F; 标记当前块中当前素数的倍数
            while(cur &lt; block_high &amp;&amp; cur &lt;&#x3D; high) &#123;
                if(cur !&#x3D; k) flags[(cur-low)&gt;&gt;1] &#x3D; 1;
                cur +&#x3D; (k &lt;&lt; 1);
            &#125;
            &#x2F;&#x2F; 找下一个素数k
            while(table[++index]);
            k &#x3D; (index &lt;&lt; 1) + 3;
        &#125;
        block++; block_low &#x3D; block_high;
    &#125;


    &#x2F;&#x2F; 各进程统计素数
    for (int i &#x3D; 0; i &lt; local_size; i++)
        if(!flags[i]) count++;

    &#x2F;&#x2F; 0号进程统计各进程的素数
    if(!rank) 
        MPI_Reduce(&amp;count, &amp;global_count, 1, MPI_INT, MPI_SUM, 0, MPI_COMM_WORLD);
    else MPI_Reduce(&amp;count, NULL, 1, MPI_INT, MPI_SUM, 0, MPI_COMM_WORLD);

    elapsed_time +&#x3D; MPI_Wtime();
    if(!rank) &#123;
        printf(&quot;运行时间: %10.6f\n&quot;, elapsed_time);
        printf(&quot;小于等于%lld一共有%d个素数\n&quot;, N, global_count);
    &#125;
    MPI_Finalize();
&#125;
