#include &lt;stdio.h&gt;
#include &lt;unistd.h&gt;
#include &lt;arpa&#x2F;inet.h&gt;
#include &lt;netdb.h&gt;
#include &lt;sys&#x2F;socket.h&gt;
#include &lt;string.h&gt;

const char* IP &#x3D; &quot;127.0.0.1&quot;;
int SERVER_PORT &#x3D; 5000;
int BUFLEN &#x3D; 1024;

int main() &#123;
    &#x2F;&#x2F; 使用 socket函数分配套接字
    int s &#x3D; socket(PF_INET, SOCK_STREAM, 0);
    if(s &lt; 0) &#123;
        printf(&quot;Can not create socket.\n&quot;);
    &#125; else printf(&quot;Socket created.\n&quot;);

    &#x2F;&#x2F; sockaddr_in结构体类型的变量，用于存储服务端信息
    struct sockaddr_in sin;
    memset(&amp;sin, 0, sizeof(sin));  &#x2F;&#x2F;归零
    sin.sin_family &#x3D; AF_INET;
    &#x2F;&#x2F; 这里写得太简单了，host还有可能是域名
    inet_pton(AF_INET, IP, &amp;sin.sin_addr.s_addr);  &#x2F;&#x2F;为什么？
    sin.sin_port &#x3D; htons(SERVER_PORT);  &#x2F;&#x2F;不要忘了转换网络字节序

    &#x2F;&#x2F; 选择本地端口号，使用connect函数即可
    if(connect(s, (struct sockaddr*)&amp;sin, sizeof(sin))&lt;0) &#123;
        printf(&quot;Connect error.\n&quot;);
    &#125; else &#123;
        printf(&quot;Connect OK!\n&quot;);
    &#125;

    &#x2F;&#x2F; 应用级协议的通信，这里只是接收数据
    char buffer[BUFLEN];
    memset(buffer, 0, BUFLEN);
    if(read(s, buffer, BUFLEN)&lt;0) &#123;
        printf(&quot;Read error.\n&quot;);
    &#125; else &#123;
        printf(&quot;Receive data:\n%s&quot;, buffer);
    &#125;  

    close(s);
    return 0;
&#125;
服务端发送数据，客户端接受数据。
int socket(int domain, int type, int protocal);


domain：域类型，即使用的协议族&#x2F;协议栈。TCP&#x2F;IP为PF_INET。
type：需要的服务类型
SOCK_STREAM: 流服务，TCP。
SOCK_DGRAM: 数据报服务，UDP。


protocol：一般取0即可。

int connect(int sockfd, (struct sockaddr*) server_addr, int sockaddr_len);
为主动套接字指明远程端点地址，参数含义如下：

sockfd：套接字描述符
server_addr：指明远程端点的结构体
sockaddr_len：地址长度（结构体大小）

int bind(int sockfd, (struct sockaddr*) my_addr, int addr_len);
为被动套接字指明一个本地端点地址。参数含义和connect一样。
int listen(int sockfd, int queue_size);


sockfd：套接字描述符
queue_size：套接字使用的队列长度，用于指定在请求队列中允许的最大请求数。

int accept(int sockfd, void* addr, int* addr_len);


sockfd：指明正在监听的套接字。
addr：存储请求连接的主机地址。
addr_len：地址的长度。

int close(int sockfd);


如果只有一个进程使用，立即终止连接并撤销套接字。
如果多个进程共享该套接字，则将引用数-1，如监听套接字。

发送和接收数据：基于数据流（TCP）发送和接收的函数send和recv，在UNIX中，可以使用read和write替代。基于数据报（UDP）发送和接收的函数需要另外掌握。
int sendto(int sockfd, const void* data, int data_len, unsigned int flags, (struct sockaddr*) remaddr, int remaddrlen);


data：要发送的数据指针。
data_len：数据的长度。
flags：一般为0。
remaddr：远端的端点地址。
remaddr_len：地址长度。

int recvfrom(int sockfd, void* buf, int buf_len, unsigned int flags, (struct sockaddr*) from, int fromlen);
参数的含义类似。









