检查HTML的标签是否闭合（假设仅出现需要闭合的标签）。

使用栈来实现即可。
from collections import deque

def solve(html: str):
    i &#x3D; 0
    stack &#x3D; deque()
    while i &lt; len(html):
        if html[i] !&#x3D; &quot;&lt;&quot;: i +&#x3D; 1;continue
        j &#x3D; i + 1;flag &#x3D; 0
        if html[j] &#x3D;&#x3D; &#39;&#x2F;&#39;: flag &#x3D; 1
        while html[j] !&#x3D; &quot;&gt;&quot;: j +&#x3D; 1
        if flag &#x3D;&#x3D; 0: stack.append(html[i+1:j])
        elif stack[-1] &#x3D;&#x3D; html[i+2:j]: stack.pop()
        else: return False
        i &#x3D; j + 1
    return True

if __name__ &#x3D;&#x3D; &quot;__main__&quot;:
    s &#x3D; &quot;&lt;html&gt;&lt;head&gt;&lt;title&gt;Example&lt;&#x2F;title&gt;&lt;&#x2F;head&gt;&lt;body&gt;&lt;h1&gt;Hello, world&lt;&#x2F;h1&gt;&lt;&#x2F;body&gt;&lt;&#x2F;html&gt;&quot;
    print(solve(s))

