套接字API








什么是套接字？
套接字的英文名是socket（插座），它是由本地的应用程序所创建，被操作系统所控制的接口。应用程序通过这个接口，可以使用传输层（TCP&#x2F;UDP）提供的服务，跨网络与其他应用进程进行通信。









套接字的表示方法？
Unix的套接字采用通用的办法，定义支持一般网络通信的函数，TCP&#x2F;IP通信是其中的一个特例，使用PF_INET表示TCP&#x2F;IP族。OS将文件描述符表用一个指针数组来表示，每个指针指向一个内部的数据结构。套接字和文件类似，每个活动的套接字都使用一个小整数来标识，称为套接字描述符。









套接字的使用？
套接字分为主动套接字和被动套接字。

主动套接字：如客户套接字
被动套接字：如服务器套接字

使用套接字时需要指明端点地址（创建时不指定）：

TCP&#x2F;IP需要指明端口号和IP地址
TCP&#x2F;IP协议族：PF_INET
TCP&#x2F;IP地址族：AF_INET

Linux内核源码中的#define AF_INET PF_INET可以看到二者是相同的，可以混用，但是他们字面意义不同，使用时尽量遵循规范：

建立socket时指定协议，即使用PF_XXX。如果是TCP&#x2F;IP协议则指定为PF_INET:
s &#x3D; socket(PF_INET, SOCKET_STREAM, 0);

设置地址时应该使用AF_XXX。
struct sockaddr sin;
menset(&amp;sin, 0, sizeof(sin));
sin.sin_family &#x3D; AF_INET; &#x2F;&#x2F;设置地址族
sin.sin_addr.s.addr &#x3D; inet_addr(IP);
sin.sin_port &#x3D; htons(PORT);
这里关系到sockaddr和sockaddr_in到区别，他们的结构体如下：
struct sockaddr &#123;
	u_char sa_len;
	u_short sa_family;
	char sa_data[14];
&#125;
struct sockaddr_in &#123;
	u_char sin_len;
	u_short sin_family;
	u_short sin_port;
	struct in_addr sin_addr;
	char sin_zero[8];
&#125;
两个结构体都占16字节，关系是：sockaddr_in是TCP&#x2F;IP的地址定义，是sockaddr的特例。一般的套接字函数都考虑考虑到通用性，需要参数为sockaddr。我们使用时需要将自己定义的sockaddr_in强制类型转化为sockaddr，以通过类型检查。


API详解先纵览C&#x2F;S各自的代码。服务端的代码示例如下：
#include &lt;stdio.h&gt;
#include &lt;unistd.h&gt;
#include &lt;string.h&gt;
#include &lt;netdb.h&gt;
#include &lt;arpa&#x2F;inet.h&gt;
#include &lt;sys&#x2F;socket.h&gt;

const char* IP &#x3D; &quot;0.0.0.0&quot;;
int PORT &#x3D; 5000;
int BUF &#x3D; 1024;

int main() &#123;
    &#x2F;&#x2F;创建listen套接字
    int s &#x3D; socket(PF_INET, SOCK_STREAM, IPPROTO_TCP);
    if(s &lt; 0) &#123;
        printf(&quot;Fail to create socket.\n&quot;);
    &#125;else printf(&quot;Successfully Create socket.\n&quot;);

    &#x2F;&#x2F;将套接字和IP、端口绑定
    struct sockaddr_in sin;
    memset(&amp;sin, 0, sizeof(sin));  &#x2F;&#x2F;每个字节都用0填充
    sin.sin_family &#x3D; AF_INET;  &#x2F;&#x2F;使用IPv4地址
    sin.sin_addr.s_addr &#x3D; inet_addr(IP);  &#x2F;&#x2F;具体的IP地址
    sin.sin_port &#x3D; htons(PORT);  &#x2F;&#x2F;端口
    bind(s, (struct sockaddr*)&amp;sin, sizeof(sin));

    &#x2F;&#x2F;进入监听状态，等待用户发起请求
    listen(s, 20);
    printf(&quot;Start server in port %d\n&quot;, PORT);

    &#x2F;&#x2F;接收客户端请求
    struct sockaddr_in cin;
    socklen_t cin_size &#x3D; sizeof(cin);
    int c &#x3D; accept(s, (struct sockaddr*)&amp;cin, &amp;clnt_size);
    if(c &lt; 0) &#123;
        printf(&quot;Connect error!\n&quot;);
    &#125; else printf(&quot;Connect success.\n&quot;);

    &#x2F;&#x2F;向客户端发送数据
    char buf[] &#x3D; &quot;Hello World!&quot;;
    write(c, buf, sizeof(buf));

    &#x2F;&#x2F;关闭套接字
    close(c);
    close(s);
    printf(&quot;Close connection.&quot;);

    return 0;
&#125;
客户端的代码如下：
#include &lt;stdio.h&gt;
#include &lt;unistd.h&gt;
#include &lt;arpa&#x2F;inet.h&gt;
#include &lt;netdb.h&gt;
#include &lt;sys&#x2F;socket.h&gt;
#include &lt;string.h&gt;

const char* IP &#x3D; &quot;127.0.0.1&quot;;
int SERVER_PORT &#x3D; 5000;
int BUFLEN &#x3D; 1024;

int main() &#123;
    &#x2F;&#x2F; 使用 socket函数分配套接字
    int s &#x3D; socket(PF_INET, SOCK_STREAM, 0);
    if(s &lt; 0) &#123;
        printf(&quot;Can not create socket.\n&quot;);
    &#125; else printf(&quot;Socket created.\n&quot;);

    &#x2F;&#x2F; sockaddr_in结构体类型的变量，用于存储服务端信息
    struct sockaddr_in sin;
    memset(&amp;sin, 0, sizeof(sin));  &#x2F;&#x2F;归零
    sin.sin_family &#x3D; AF_INET;
    &#x2F;&#x2F; 这里写得太简单了，host还有可能是域名
    inet_pton(AF_INET, IP, &amp;sin.sin_addr.s_addr);  &#x2F;&#x2F;为什么？
    sin.sin_port &#x3D; htons(SERVER_PORT);  &#x2F;&#x2F;不要忘了转换网络字节序

    &#x2F;&#x2F; 选择本地端口号，使用connect函数即可
    if(connect(s, (struct sockaddr*)&amp;sin, sizeof(sin))&lt;0) &#123;
        printf(&quot;Connect error.\n&quot;);
    &#125; else &#123;
        printf(&quot;Connect OK!\n&quot;);
    &#125;

    &#x2F;&#x2F; 应用级协议的通信，这里只是接收数据
    char buffer[BUFLEN];
    memset(buffer, 0, BUFLEN);
    if(read(s, buffer, BUFLEN)&lt;0) &#123;
        printf(&quot;Read error.\n&quot;);
    &#125; else &#123;
        printf(&quot;Receive data:\n%s&quot;, buffer);
    &#125;  

    close(s);
    return 0;
&#125;
