glLineWidth()
线的宽度


glShaderModel()
面的着色模式


上面三个都挺好理解，我们来看看最后一个 glShaderModel()。
这个函数可选属性有 GL_SMOOTH和 GL_FLAT，我们通过程序来对比一下二者的区别:


从上图我们可以很直观得看出： GL_SMOOTH的；GL_FLAT的。

练习编写程序画出下面一个图形：

我们一起来分析一下这个图形的构成。首先背景和之前一样都是灰色的；。
最基本的想法是用正多边形来逼近圆，这可以作为边框的画法，但不能实现内部的渐变。要实现渐变，我们可以使用：三角形的一个顶点始终在圆心，另外两个顶点就在圆上——使用很多个三角面片即可组成圆。
我们首先定义一些要用的常量：
#define PI 3.1415926535f
#define RADIUS 0.8f&#x2F;&#x2F;圆的半径

然后是圆形边框的绘制：
void border()&#123;
    glColor3f(1,1,1);
    glLineWidth(6.5);
    glBegin(GL_LINE_LOOP);
    for(int i&#x3D;0;i&lt;100;i++)&#123;
        GLfloat angle&#x3D;(float)i&#x2F;100*2*PI;
        glVertex2f(RADIUS*cos(angle),RADIUS*sin(angle));
    &#125;
    glEnd();
&#125;

再然后是内部填充的绘制：
void fill()&#123;
    glBegin(GL_TRIANGLE_FAN);
    GLfloat temp&#x3D;0;
    for(int i&#x3D;1;i&lt;&#x3D;100;i++)&#123;
        GLfloat angle&#x3D;(float)i&#x2F;100*2*PI;
        glColor3f(0.3,0.3,0.3);
        glVertex2f(0,0);
        glColor3f(0.8,0.8,0.8);
        glVertex2f(RADIUS*cos(angle),RADIUS*sin(angle));
        glVertex2f(RADIUS*cos(temp),RADIUS*sin(temp));
        temp&#x3D;angle;
    &#125;
    glEnd();
&#125;

最后显示函数调用两个函数即可：（注意调用的顺序）
void display()&#123;
    glClear(GL_COLOR_BUFFER_BIT);
    fill();
    border();
    glFlush();
&#125;

程序的源代码如下：
#include &lt;glut.h&gt;
#include &lt;cmath&gt;

#define PI 3.1415926535f
#define RADIUS 0.8f&#x2F;&#x2F;圆的半径

void border()&#123;
    glColor3f(1,1,1);
    glLineWidth(6.5);
    glBegin(GL_LINE_LOOP);
    for(int i&#x3D;0;i&lt;100;i++)&#123;
        GLfloat angle&#x3D;(float)i&#x2F;100*2*PI;
        glVertex2f(RADIUS*cos(angle),RADIUS*sin(angle));
    &#125;
    glEnd();
&#125;

void fill()&#123;
    glBegin(GL_TRIANGLE_FAN);
    GLfloat temp&#x3D;0;
    for(int i&#x3D;1;i&lt;&#x3D;100;i++)&#123;
        GLfloat angle&#x3D;(float)i&#x2F;100*2*PI;
        glColor3f(0.3,0.3,0.3);
        glVertex2f(0,0);
        glColor3f(0.8,0.8,0.8);
        glVertex2f(RADIUS*cos(angle),RADIUS*sin(angle));
