class Solution &#123;
public: 
    string reverseWords(string&amp; s) &#123;
        int length &#x3D; s.length();
        int i &#x3D; 0;
        while (i &lt; length) &#123;
            int start &#x3D; i;
            while (i &lt; length &amp;&amp; s[i] !&#x3D; &#39; &#39;) &#123;
                i++;
            &#125;
            int left &#x3D; start, right &#x3D; i - 1;
            while (left &lt; right) &#123;
                swap(s[left], s[right]);
                left++;
                right--;
            &#125;
            while (i &lt; length &amp;&amp; s[i] &#x3D;&#x3D; &#39; &#39;) i++;
        &#125;
        return s;
    &#125;
&#125;;




链表的中间结点给定一个头结点为 head 的非空单链表，返回链表的。
