使用快慢指针。一个指针再前，另一个指针在其后N个结点的位置处。两个指针一起移动，直至前指针到达表尾。
class Solution &#123;
public:
    ListNode* removeNthFromEnd(ListNode* head, int n) &#123;
        ListNode* dummy &#x3D; new ListNode(0, head);
        ListNode* first &#x3D; head;
        ListNode* second &#x3D; dummy;
        for (int i &#x3D; 0; i &lt; n; ++i) &#123;
            first &#x3D; first-&gt;next;
        &#125;
        while (first) &#123;
            first &#x3D; first-&gt;next;
            second &#x3D; second-&gt;next;
        &#125;
        second-&gt;next &#x3D; second-&gt;next-&gt;next;
        ListNode* ans &#x3D; dummy-&gt;next;
        delete dummy;
        return ans;
    &#125;
&#125;;







