有序数组的平方给你一个按 非递减顺序 排序的整数数组 nums，返回 每个数字的平方 组成的新数组，要求也按 非递减顺序 排序。

示例 1：输入：nums &#x3D; [-4,-1,0,3,10] 输出：[0,1,9,16,100]
示例 2：输入：nums &#x3D; [-7,-3,2,3,11] 输出：[4,9,9,49,121]

从正负分界处切断，两段的平方都是有序的。再利用的思想对两段进行合并。
class Solution &#123;
public:
    vector&lt;int&gt; sortedSquares(vector&lt;int&gt;&amp; nums) &#123;
        vector&lt;int&gt; vi;
        int j&#x3D;0,len&#x3D;nums.size();
        while(j&lt;len &amp;&amp; nums[j]&lt;0) j++;
        int i&#x3D;j-1;
        while(i&gt;&#x3D;0 || j&lt;len)&#123;
            if(i&lt;0)&#123;
                vi.push_back(nums[j]*nums[j]);
                j++;
            &#125;
            else if(j&gt;&#x3D;len)&#123;
                vi.push_back(nums[i]*nums[i]);
                i--;
            &#125;
            else if((nums[i]+nums[j])&lt;0)&#123;
                vi.push_back(nums[j]*nums[j]);
                j++;
            &#125;
            else&#123;
                vi.push_back(nums[i]*nums[i]);
                i--;
            &#125;
        &#125;
        return vi;
    &#125;
&#125;;


从两端开始，往中间收拢，性能极高。
class Solution &#123;
public:
    vector&lt;int&gt; sortedSquares(vector&lt;int&gt;&amp; nums) &#123;
        int i&#x3D;0,j&#x3D;nums.size()-1,flag&#x3D;j;
        vector&lt;int&gt; vi(j+1);
        while(flag&gt;&#x3D;0)&#123;
            if(abs(nums[i])&gt;abs(nums[j]))&#123;
                vi[flag]&#x3D;(nums[i]*nums[i]);
                i++;
            &#125;
            else&#123;
                vi[flag]&#x3D;(nums[j]*nums[j]);
                j--;
            &#125;
            flag--;
        &#125;
        return vi;
    &#125;
&#125;;





对比第一种和第二种方法，两者时间的差别主要在于是否去寻找了分段点。显然，这一步操作的时间复杂度也是$O(n)$。
双指针的思想主要就是两个指针像两边移动或向中间靠拢，然后达到边界条件。

轮转数组给你一个数组，将数组中的元素向右轮转 k 个位置，其中 k 是非负数。

示例 1：输入: nums &#x3D; [1,2,3,4,5,6,7], k &#x3D; 3  输出: [5,6,7,1,2,3,4]
示例 2：输入：nums &#x3D; [-1,-100,3,99], k &#x3D; 2  输出：[3,99,-1,-100]

双指针，使用递归。。而且还在参数列表处额外加了一个默认参数，有点……
class Solution &#123;
public:
    void rotate(vector&lt;int&gt;&amp; nums,int k,int pos&#x3D;0)&#123;
        int n&#x3D;nums.size(),i&#x3D;pos;
        k&#x3D;k%n;
        if(k&#x3D;&#x3D;0) return;
        for(;i&lt;n-k;i++)
            swap(nums[i],nums[n+(i-pos)%k-k]);
        if(i&#x3D;&#x3D;n+(i-pos)%k-k) return;
        rotate(nums,k-(i-pos)%k,n-k);
    &#125;
&#125;;

解释：两个指针，左指针一直往右移动，右指针在一个区域内循环移动，每一步都交换两指针指向的值。

