public:
    int _a;
    char _b;
    int add()&#123;
        return (_a+_b);
    &#125;
    MyClass(int a,char b)&#123;
        _a&#x3D;a;
        _b&#x3D;b;
    &#125;
&#125;;
int main()&#123;
    MyClass m(1,2),n(3,4);
    std::cout&lt;&lt;m.add();
    return 0;
&#125;

值得注意的是，构造函数必须是，不然编译器会报错！









